1	function cellKey(x: number, y: number): string {
2	  return `${x},${y}`;
3	}
4	
5	function parseKey(key: string): [number, number] {
6	  const [x, y] = key.split(",").map(Number);
7	  return [x, y];
8	}
9	
10	export function nextGeneration(liveCells: [number, number][]): [number, number][] {
11	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
12	  const neighborCounts = new Map<string, number>();
13	
14	  for (const [x, y] of liveCells) {
15	    for (let dx = -1; dx <= 1; dx++) {
16	      for (let dy = -1; dy <= 1; dy++) {
17	        if (dx === 0 && dy === 0) continue;
18	        const key = cellKey(x + dx, y + dy);
19	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
20	      }
21	    }
22	  }
23	
24	  const result: [number, number][] = [];
25	  for (const [key, count] of neighborCounts) {
26	    const isAlive = liveSet.has(key);
27	    if (count === 3 || (isAlive && count === 2)) {
28	      result.push(parseKey(key));
29	    }
30	  }
31	
32	  return result;
33	}
